// Parse & sanitize input, detect language via Unicode script ranges
const body = $('Webhook - HR Bot Chat').first().json.body;
const rawMessage = $input.first().json.message || body.message || '';

// Sanitize inputs to prevent SQL injection and abuse
const sanitizedMobile = (body.mobile_number || '').replace(/[^0-9+\-\s]/g, '').trim().substring(0, 20);
const sanitizedEmail  = (body.email_id || '').trim().toLowerCase().substring(0, 100);
const message         = rawMessage.trim().substring(0, 2000); // limit message length

function detectLanguage(text) {
  if (/[\u0900-\u097F]/.test(text)) {
    // Devanagari — distinguish Marathi from Hindi by common Marathi-only characters
    if (/[\u0902\u0948\u094D][\u0915-\u0939]/.test(text) && /आहे|आहेत|मला|आपण/.test(text)) return 'mr';
    return 'hi';
  }
  if (/[\u0A80-\u0AFF]/.test(text)) return 'gu';
  if (/[\u0B80-\u0BFF]/.test(text)) return 'ta';
  if (/[\u0C00-\u0C7F]/.test(text)) return 'te';
  if (/[\u0C80-\u0CFF]/.test(text)) return 'kn';
  if (/[\u0D00-\u0D7F]/.test(text)) return 'ml';
  if (/[\u0980-\u09FF]/.test(text)) return 'bn';
  if (/[\u0A00-\u0A7F]/.test(text)) return 'pa';
  return 'en';
}

const userLanguage     = body.language || 'auto';
const detectedLanguage = userLanguage === 'auto' ? detectLanguage(message) : userLanguage;

const languageConfig = {
  'en': { name: 'English',   needsTranslation: false },
  'hi': { name: 'Hindi',     needsTranslation: true  },
  'gu': { name: 'Gujarati',  needsTranslation: true  },
  'mr': { name: 'Marathi',   needsTranslation: true  },
  'ta': { name: 'Tamil',     needsTranslation: true  },
  'te': { name: 'Telugu',    needsTranslation: true  },
  'kn': { name: 'Kannada',   needsTranslation: true  },
  'ml': { name: 'Malayalam', needsTranslation: true  },
  'bn': { name: 'Bengali',   needsTranslation: true  },
  'pa': { name: 'Punjabi',   needsTranslation: true  }
};

const langConfig  = languageConfig[detectedLanguage] || languageConfig['en'];
const sessionId   = body.session_id || `session_${sanitizedMobile || sanitizedEmail}_${Date.now()}`;

return {
  json: {
    userMessage:       message,
    originalMessage:   message,
    detectedLanguage,
    languageName:      langConfig.name,
    needsTranslation:  langConfig.needsTranslation,
    mobileNumber:      sanitizedMobile,
    emailId:           sanitizedEmail,
    sessionId,
    messageType:       body.message_type || 'text',
    isAudio:           body.is_audio === 'true' || body.is_audio === true,
    timestamp:         new Date().toISOString(),
    requestId:         `req_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`
  }
};

