// Merge employee DB record with language/session context
let languageContext = {};
try { languageContext = $('Merge Translation Context').first().json; } catch (e) {}
if (!languageContext || Object.keys(languageContext).length === 0) {
  try { languageContext = $('Skip Translation (English)').first().json; } catch (e) {}
}

const row = $('Fetch Employee Data').first().json;

return {
  json: {
    // Employee profile
    employeeId:         row.id,
    employeeNumber:     row.employee_number,
    displayName:        row.display_name,
    email:              row.email,
    mobilePhone:        row.mobile_phone,
    dateJoined:         row.date_joined,
    employmentStatus:   row.employment_status,
    departmentId:       row.department_id,
    locationId:         row.location_id,
    jobTitleId:         row.job_title_id,
    reportingManagerId: row.reporting_manager_id,
    companyId:          row.company_id,
    inProbation:        row.in_probation,
    probationEndDate:   row.probation_end_date,
    // Pinecone namespace (from companies JOIN) — filters policies to this company
    policyNamespace:    row.policy_namespace || '',
    // Language & session context
    userMessage:        languageContext.userMessage,
    translatedMessage:  languageContext.translatedMessage,
    detectedLanguage:   languageContext.detectedLanguage,
    sessionId:          languageContext.sessionId,
    timestamp:          languageContext.timestamp,
    requestId:          languageContext.requestId
  }
};

const finalResponse   = $input.first().json.output;
const ctx             = $('Merge Employee & Language Context').first().json;

// Contextual quick actions based on response content
const quickActions = [];
const lower = finalResponse.toLowerCase();

if (lower.includes('leave balance') || lower.includes('available')) {
  quickActions.push(
    { label: 'Apply for Leave',    action: 'apply_leave'        },
    { label: 'View Leave History', action: 'view_leave_history' }
  );
}
if (lower.includes('salary') || lower.includes('payslip') || lower.includes('ctc')) {
  quickActions.push(
    { label: 'Download Payslip',      action: 'download_payslip'    },
    { label: 'View Salary Structure', action: 'view_salary_structure' }
  );
}
if (lower.includes('manager') || lower.includes('reporting')) {
  quickActions.push(
    { label: 'Contact Manager', action: 'contact_manager' }
  );
}

// Suggested follow-up questions in user's language
const relatedQuestions = {
  'en': ['What is my leave balance?', 'Show my recent leave history', 'Who is my reporting manager?', 'What is the company leave policy?'],
  'hi': ['मेरी छुट्टी शेष राशि क्या है?', 'मेरा हाल का छुट्टी इतिहास दिखाएं', 'मेरा रिपोर्टिंग मैनेजर कौन है?', 'कंपनी की छुट्टी नीति क्या है?'],
  'gu': ['મારી રજા બાકી કેટલી છે?', 'મારો તાજેતરનો રજા ઇતિહાસ બતાવો', 'મારો રિપોર્ટિંગ મેનેજર કોણ છે?', 'કંપનીની રજા નીતિ શું છે?'],
  'mr': ['माझी रजा शिल्लक किती आहे?', 'माझा अलीकडील रजा इतिहास दाखवा', 'माझा रिपोर्टिंग मॅनेजर कोण आहे?', 'कंपनीचे रजा धोरण काय आहे?']
};

const lang             = ctx.detectedLanguage || 'en';
const suggestedQns     = relatedQuestions[lang] || relatedQuestions['en'];
const processingTimeMs = Date.now() - new Date(ctx.timestamp).getTime();

return {
  json: {
    success: true,
    data: {
      message:           finalResponse,
      original_message:  ctx.userMessage,
      quick_actions:     quickActions,
      related_questions: suggestedQns,
      metadata: {
        employee_id:        ctx.employeeId,
        employee_name:      ctx.displayName,
        company_id:         ctx.companyId,
        policy_namespace:   ctx.policyNamespace,
        detected_language:  ctx.detectedLanguage,
        was_translated:     ctx.detectedLanguage !== 'en',
        session_id:         ctx.sessionId,
        request_id:         ctx.requestId,
        timestamp:          new Date().toISOString(),
        processing_time_ms: processingTimeMs
      }
    }
  }
};
